/* --------------------------------------------------------------------------------------------
 * MAJOR BLESSING LEVEL-UP CURRENCY — 4 distinct currencies, keyed by god index. CONFIRMED
 * verbatim at N.js:17099-17102 and again (identical branch) at N.js:17137-17138 (the altar's
 * "level up blessing" click handler), stitched:
 *
 *   cost = GodsInfo[godIdx][4] * Math.pow(GodsInfo[godIdx][5], Divinity[28+godIdx])   // current
 *          blessing level = Divinity[28+godIdx]; gate: that level < BlessingMaxLV(0,0)
 *   0==godIdx||8==godIdx||4==godIdx||2==godIdx : pay from Gaming[0]                    (BITS)
 *   1==godIdx                                   : pay from Sailing[1][0]                (SAILING GOLD
 *                                                  — savemap/sailing.mjs:19 already documents
 *                                                  Sailing[1][0] as the sailing treasure amount)
 *   3==godIdx||6==godIdx                        : pay from Money                        (COINS)
 *   else (5,7,9)                                 : pay from Divinity[39]                 (PARTICLES
 *                                                  — confirms the research brief's 4th currency.
 *                                                  Divinity[39] is fed by the `"GiveAtoms"==d:
 *                                                  Divinity[39]+=e` action at N.js:12515 and spent
 *                                                  by the Atom Collider's own AtomCost/AtomThreshold
 *                                                  functions (N.js:17156/17166) — despite the
 *                                                  internal action name "GiveAtoms", this is the
 *                                                  raw PARTICLES balance you collect, NOT the atom
 *                                                  slot LEVELS (those live in the separate "Atoms"
 *                                                  save array, gamedata-w3-atoms.mjs). Cross-checked
 *                                                  against idleon-toolbox's
 *                                                  parsers/world-5/divinity.ts:113
 *                                                  (`account?.atoms?.particles`) — exact agreement,
 *                                                  toolbox already names this currency "particles".)
 *   On success: currency -= cost; Divinity[28+godIdx] += 1 (one level per purchase, no bulk-buy).
 *   costToMax(level) = sum_{i=level}^{maxLevel-1} GodsInfo[g][4] * GodsInfo[g][5]^i — not read
 *   directly in N.js's altar UI (which only ever buys one level at a time) but a natural/obvious
 *   extension; idleon-toolbox/parsers/world-5/divinity.ts:72-78 `getCostToMax` computes exactly
 *   this sum, confirming the per-level cost formula it's built from matches this file's.
 * -------------------------------------------------------------------------------------------- */
export const BLESSING_CURRENCY_BY_GOD = {
  0: "bits", 1: "sailingGold", 2: "bits", 3: "coins", 4: "bits",
  5: "particles", 6: "coins", 7: "particles", 8: "bits", 9: "particles",
};

/* --------------------------------------------------------------------------------------------
 * BlessingMaxLV — the shared (same for all 10 gods) blessing level cap. Verbatim, N.js:17809:
 *   BlessingMaxLV() = Math.round(100 + CoralKidUpgBonus(1,0) + Minehead("BonusQTY",9,0)
 *                                     + Summoning("VaultUpgBonus",76,0))
 * i.e. base 100, +CoralKid tier-1 upgrade, +Minehead bonus-qty-9, +Vault upgrade-76. All three
 * additive bonuses are NOT yet extracted anywhere in this repo (grepped bonuses/ and gamedata* —
 * no Minehead or Summoning-VaultUpgBonus-76 or Thingies-CoralKidUpgBonus-1 hits); hand these three
 * dispatcher calls to whichever agent owns Minehead/Summoning/CoralKid tables.
 * -------------------------------------------------------------------------------------------- */
export const BLESSING_MAX_LV_BASE = 100;
export const BLESSING_MAX_LV_FORMULA =
  "Math.round(100 + Thingies('CoralKidUpgBonus',1,0) + Minehead('BonusQTY',9,0) + Summoning('VaultUpgBonus',76,0))  // N.js:17809";

/* --------------------------------------------------------------------------------------------
 * MAJOR BLESSING CURVE — "BlesssBonus" (verbatim spelling, triple-s, NOT "BlessingBonus"),
 * N.js:17809-17811 stitched. Returns a PERCENT (consumers do `1 + BlesssBonus(...)/100`, see
 * DivMulti below). Args: Divinity("BlesssBonus", godIdx, 0).
 *
 *   if in Tutorial scene: return 0
 *   if godIdx == 2 (Nobisect — "god#2 capped", confirms the research brief):
 *     f = Math.max(1,
 *           SkillStats("AllEfficiencies")
 *           + Math.pow((AlchBubbles.MinEff + AlchBubbles.ChopEff)/100, 2)
 *           + Math.pow((TotalStats("STR") + TotalStats("AGI") + TotalStats("WIS"))/3, 0.5)/7)
 *     DNSM.BlessyBunDN = f   // cached for the tooltip/redraw path
 *     return Divinity[28+2] * GodsInfo[2][14]
 *            * Math.min(1.8, Math.max(0.1,
 *                4 * Math.pow(0.01 * ((BlessyBunDN + 1E4) / Math.max(10*BlessyBunDN + 10, 1)), 2)))
 *     // i.e. Nobisect's curve is capped to a [0.1x, 1.8x] MULTIPLIER on (level*blessingMulti),
 *     // NOT the emporium-scaled formula every other god uses — verbatim confirmation of "god#2
 *     // capped" from the research brief. MISMATCH vs idleon-toolbox: divinity.ts:34-36 instead
 *     // computes `blessingBonus = level*blessingMultiplier*emporiumBonus` (the GENERIC formula)
 *     // and then does `Math.min(blessingBonus, 500)` — a flat 500 CAP ON THE FINAL VALUE, not
 *     // the BlessyBunDN-derived [0.1x,1.8x] multiplier N.js actually computes. These are two
 *     // structurally different formulas (toolbox's is a simplification/approximation, possibly
 *     // stale) — this file's version was read directly off the freshly-stitched N.js text at
 *     // N.js:17809-17810 and is verbatim, so treat toolbox's `Math.min(x,500)` as unverified.
 *   else (all other 9 gods):
 *     return Divinity[28+godIdx] * GodsInfo[godIdx][14]
 *            * (1 + 0.05 * Ninja("EmporiumBonus",33,0) * Math.max(0, Divinity[25] - 10))
 *     // <level> * <blessingMulti> * <emporium jade scaler>. THIS is the "emporium jade scaler"
 *     // the brief asked for: Ninja("EmporiumBonus",33,0) is the Jade Emporium node-33 bonus
 *     // (0.05 = 5% per point), gated to only apply once GOD_RANK (Divinity[25]) exceeds 10
 *     // (i.e. once every god is unlocked) — Math.max(0, Divinity[25]-10).
 * -------------------------------------------------------------------------------------------- */
export const BLESS_MAJOR_FORMULA_DEFAULT =
  "Divinity[28+godIdx] * GodsInfo[godIdx][14] * (1 + 0.05*Ninja('EmporiumBonus',33,0)*Math.max(0,Divinity[25]-10))  // N.js:17811, all gods except idx 2";
export const BLESS_MAJOR_FORMULA_NOBISECT =
  "Divinity[28+2] * GodsInfo[2][14] * Math.min(1.8, Math.max(0.1, 4*Math.pow(0.01*((BlessyBunDN+1E4)/Math.max(10*BlessyBunDN+10,1)),2)))  // N.js:17809-17810, god idx 2 only; BlessyBunDN = Math.max(1, SkillStats('AllEfficiencies') + ((AlchBubbles.MinEff+AlchBubbles.ChopEff)/100)^2 + ((STR+AGI+WIS)/3)^0.5/7)";

/* --------------------------------------------------------------------------------------------
 * Bonus_MAJOR(charIdx, e) — boolean gate (1/0): "does character charIdx currently have MAJOR
 * bonus category e active". Verbatim, N.js:17811-17820, stitched. `e` here is compared against
 * GodsInfo[linkedGodIdx][13] (the TYPE field, a bijection of god index — NOT god index itself in
 * general; see GODS_INFO_FULL[].type notes above for the fixed points / 2-cycle / 3-cycle).
 *
 *   if in Tutorial: return 0
 *   if Companions(0)==1                                            // "Companion of the Gods" upgrade
 *      || Holes("PocketDivOwned",e,0)==1                           // a Cavern pocket-item grants it
 *      || W7divChosen()==e                                          // W7 crossover "chosen god" pick
 *                                                                    // (OptionsListAccount[425]-1
 *                                                                    //  indexes GodsInfo; NOT
 *                                                                    //  transcribed further — W7,
 *                                                                    //  out of W5 scope)
 *      || (ResearchStuff("Grid_Bonus",173,0) >= 1 && e==2)          // "Divine Design" research node
 *      || (GemItemsPurchased[9]==1 && e==0)                         // a gem-shop unlock
 *   : return 1
 *   if e==6: return ActorEvents_577._GenINFO[87]==1 ? 1 : 0   // "is ANY char linked to Purrmep"
 *   if e==8: return ActorEvents_577._GenINFO[210]==1 ? 1 : 0  // "is ANY char linked to Kattlekruk"
 *      // These two flags are recomputed every frame by scanning Divinity[12..23] (the 12 linked-god
 *      // slots) for any entry whose type==6 or type==8 — see N.js:17085-17088/17495-17498 verbatim
 *      // below. They enforce Purrmep/Kattlekruk's own flavor text: "Only 1 player can link" —
 *      // account-wide exclusive god links, the OTHER 8 gods have no such restriction.
 *   if Divinity[charIdx+12] == -1: return 0                        // this char has no linked god
 *   if GodsInfo[Divinity[charIdx+12]][13] == e: return 1           // linked god's type matches e
 *   else:                                                           // "God Rank" (SkillLevels[505])
 *     // fallback — SAME shape as Bonus_Minor's documented fallback in bonuses/divinity.mjs:
 *     if SkillLevels[505] (this char) > 0:
 *       f = GodsInfo[ SkillLevels[505] - 10*Math.floor(SkillLevels[505]/10) ][13] == e
 *     else f = false
 *     return f && Divinity[25] > (SkillLevels[505] - 10*Math.floor(SkillLevels[505]/10)) ? 1 : 0
 *
 * EXCLUSIVE-LINK FLAG SOURCE, N.js:17085-17088 (verbatim, runs once per altar-actor tick):
 *   _GenINFO[87] = 0; _GenINFO[207] = 0
 *   for slot in 0..11:                               // Divinity[12..23], 12 possible linked-god slots
 *     if Divinity[12+slot] >= 0:
 *       if GodsInfo[Divinity[12+slot]][13] == 6: _GenINFO[87] = 1
 *       if GodsInfo[Divinity[12+slot]][13] == 8: _GenINFO[207] = 1
 *
 * CONSUMERS (not this file's job to implement, listed for the recipe-owning agent):
 *   N.js:5359/5361 Total-Damage-ish formula reads `Divinity("Bonus_MAJOR",charIdx,7)` directly
 *   (Flutterbis's type, "2x kills counted") — mentioned in the research brief as unresolved;
 *   confirmed the case body above is what answers that call. N.js:17811 & N.js:17834
 *   (DivPTSPerHr / DivPerHr_EXP, both in this file below) read `Bonus_MAJOR(0,6)` (Purrmep) as a
 *   flat `Math.max(1,1+Bonus_MAJOR(0,6))` gate — i.e. a boolean bonus, not a scaled one, for those
 *   two specific formulas.
 * -------------------------------------------------------------------------------------------- */

/* --------------------------------------------------------------------------------------------
 * DivMulti(slot) / DivMultiTOTAL — the 6-term multiplier chain that feeds DivPTSPerHr and
 * DivPerHr_EXP (both below). Verbatim, N.js:17823-17824. NOTE only 4 of the 10 gods' major
 * blessings (0,1,3,5 = Snehebatu/Arctis/Harriep/Omniphau) are wired into this chain via
 * BlesssBonus — Nobisect(2) and Goharut(4)'s blessings are NEVER read here (their % bonuses must
 * be consumed by other, god-specific stat formulas elsewhere, not this Divinity-output
 * multiplier), and the LAST TWO slots read Sailing artifact bonuses instead of any god blessing:
 *
 *   DivMulti(0) = 1 + BlesssBonus(0,0)/100         // Snehebatu major
 *   DivMulti(1) = 1 + BlesssBonus(1,0)/100         // Arctis major
 *   DivMulti(2) = 1 + Sailing("ArtifactBonus",11,0)/100
 *   DivMulti(3) = 1 + BlesssBonus(3,0)/100         // Harriep major
 *   DivMulti(4) = 1 + BlesssBonus(5,0)/100         // Omniphau major (NOTE: slot 4 -> god idx 5)
 *   DivMulti(else, i.e. 5) = 1 + Sailing("ArtifactBonus",18,0)/100
 *   DivMultiTOTAL = Math.max(1, DivMulti(0)*DivMulti(1)*DivMulti(2)*DivMulti(3)*DivMulti(4)*DivMulti(5))
 * -------------------------------------------------------------------------------------------- */
export const DIV_MULTI_SLOT_GOD = { 0: 0, 1: 1, 3: 3, 4: 5 };   // slot -> god idx (slots 2,5 = Sailing artifacts, not a god)

/* --------------------------------------------------------------------------------------------
 * GOD-UNLOCK PROGRESSION — "GOD_RANK" (Divinity[25]) is the account-wide counter that gates
 * which of the 10 gods are visible/selectable at all. CONFIRMED N.js:17102/17104/17495 (the
 * altar-overview click/render hit-test loop): a god icon at slot e is only interactive when
 * `Divinity[25] > e` (i.e. need GOD_RANK >= e+1 to unlock god e); the UI literal at N.js:17117-
 * 17118 draws GodsInfo[Divinity[25]][7] (that NEXT god's "please me" flavor line) while
 * GOD_RANK<10, and "____________You_have_pleased_all_known_divinities!" once GOD_RANK>=10.
 * GOD_RANK is advanced via the "Offering" mini-game (verbatim below), and the UI literally
 * labels it "GOD_RANK;..." at N.js:17120.
 *
 * OFFERING mechanic (spends DIVINITY POINTS — Divinity[24] — NOT bits/gold/coins/atoms):
 *   Divinity[24] += <amount>   whenever "Divinity_PTS"-typed AFK gains are claimed — CONFIRMED
 *     N.js:8077: `"Divinity_PTS"==_GainsDisplayList[f][0] && Divinity[24] += _GainsDisplayList[f][1]`.
 *     (Divinity Points/hr is computed by DivPTSPerHr below — the same rate consumers see on the
 *     "/hr" HUD label, N.js:17130.) Divinity[24] ALSO doubles as currency for CoralKid upgrades
 *     (Thingies("CoralKidUpgCost",...), N.js:21665-21729) — the very upgrades that boost several
 *     of Divinity's own arms (CoralKidUpgBonus 0-4, see BIG_P section below). Same pool, two sinks.
 *
 *   OfferingCost(tier,0) — N.js:17824-17825, verbatim (tier = Divinity[b+26], a per-attempt
 *   0-4 "confidence" tier the player picks, see OfferingOdds below):
 *     base = (20 * Math.pow(GOD_RANK+1.3, 2.3) * Math.pow(2.2, GOD_RANK) + 60) * OfferingOdds(tier,0)
 *     if GOD_RANK > 2:
 *       base *= Math.pow(Math.min(1.8, Math.max(1, 1 + ServerVarLoad("DivCostAfter3")/100)), GOD_RANK-2)
 *     return base<1 ? 1 : base<1E6 ? Math.ceil(base) : base
 *   OfferingOdds(tier,0) — N.js:17825-17826, verbatim:
 *     tier==0 -> 1%, tier==1 -> 5%, tier==2 -> 10%, tier==3 -> 25%, tier==4 -> 50%, else -> 100%
 *   Attempt resolution (altar click handler, N.js:17088, verbatim):
 *     if Divinity[24] >= OfferingCost(tier,0):
 *       // Y4 alchemy bubble: up to 35% chance to skip paying the cost even on this attempt
 *       if NOT (random() < Math.min(0.35, AlchBubbles.Y4/100)):
 *         Divinity[24] -= OfferingCost(tier,0)
 *       if random() < OfferingOdds(tier,0):        // success
 *         GOD_RANK (Divinity[25]) += 1
 *         // Divinity[26]/[27] get re-rolled (cosmetic reward-tier RNG for the offering-result
 *         // popup, N.js:17091 — not a stat, not transcribed further)
 * -------------------------------------------------------------------------------------------- */
export const GOD_RANK_MAX = 10;
export const OFFERING_ODDS_BY_TIER = [0.01, 0.05, 0.10, 0.25, 0.50];   // tier 0-4; tier>=5 (unreachable via UI) = 1.0

